import{c as o,Q as a,j as t,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I enforce MFA across my organisation?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/enforce-mfa.md","filePath":"guide/recipes/portal/enforce-mfa.md","lastUpdated":1779094756000}'),n={name:"guide/recipes/portal/enforce-mfa.md"};function i(s,e,l,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-enforce-mfa-across-my-organisation" tabindex="-1">How do I enforce MFA across my organisation? <a class="header-anchor" href="#how-do-i-enforce-mfa-across-my-organisation" aria-label="Permalink to &quot;How do I enforce MFA across my organisation?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>MFA enforcement applies to your <strong>internal</strong> users — people whose identity is owned by your customer. External users (signed in via SSO from another organisation) follow their home organisation&#39;s policy.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Settings → Security</strong>.</li><li>Find the <strong>MFA Policy</strong> section.</li><li>Turn on <strong>Require MFA</strong>.</li><li>(Optional) Pick the allowed second factors. By default both <strong>TOTP</strong> (authenticator app) and <strong>WebAuthn</strong> (passkey / hardware key) are allowed.</li><li>(Optional) Set the <strong>MFA enrolment grace period</strong> — how long an existing user can keep signing in without enrolling. Default is no grace.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li>New invitees are required to enrol an MFA method before they finish account setup.</li><li>Existing users without MFA are blocked at next sign-in (after the grace period, if any) and walked through enrolment.</li><li>The Users table shows an <strong>MFA</strong> column so you can audit who has enrolled.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../account/enroll-authenticator">How do I enroll an authenticator app?</a></li><li><a href="./../account/add-passkey">How do I add a passkey?</a></li><li><a href="./configure-sso">How do I configure SSO?</a></li></ul>',9)])])}const g=o(n,[["render",i]]);export{p as __pageData,g as default};
